const message = $input.item.json.body.message || '';
const user = $input.item.json.body.user || { name: 'Guest', role: 'Guest', id: null };
const normalized = message.toLowerCase();

let intent = 'general';
let searchQuery = '';
let orderNumber = '';

const orderMatch = normalized.match(/(or-[a-z0-9\-]+)/i);

function cleanQuery(text) {
  let cleaned = text.replace(/[?,.\!]/g, ' ');
  let words = cleaned.toLowerCase().split(/\s+/);
  const stopWords = new Set([
    'apakah', 'adakah', 'ada', 'berapa', 'harga', 'stok', 'jual', 'daftar', 'tampilkan', 'cari',
    'tentang', 'toko', 'tani', 'petani', 'mitra', 'penjual', 'order', 'pesanan', 'beli', 'transaksi',
    'di', 'ke', 'dari', 'ini', 'itu', 'yang', 'saya', 'ingin', 'mau', 'tolong', 'info', 'informasi',
    'detail', 'untuk', 'dong', 'kak', 'min', 'gan', 'bos', 'ya', 'sih', 'kah', 'permisi', 'halo',
    'selamat', 'pagi', 'siang', 'sore', 'malam', 'list', 'status', 'cek', 'ketersediaan', 'bagaimanakah',
    'bagaimana', 'mana', 'di mana', 'lokasi', 'alamat', 'kontak', 'wa', 'nomor', 'hp', 'telepon', 'hubungi',
    'bisa', 'tunjukkan', 'kasih', 'tahu', 'tau', 'lihat'
  ]);
  let queryWords = words.filter(w => !stopWords.has(w) && w.length > 0);
  return queryWords.join(' ');
}

if (orderMatch) {
  intent = 'specific_order';
  orderNumber = orderMatch[1].toUpperCase();
} else if (
  normalized.includes('fitur') ||
  normalized.includes('bantuan') ||
  normalized.includes('cara') ||
  normalized.includes('aplikasi') ||
  normalized.includes('menu') ||
  normalized.includes('tutorial') ||
  normalized.includes('panduan')
) {
  intent = 'general';
} else if (
  normalized.includes('produk') ||
  normalized.includes('stok') ||
  normalized.includes('harga') ||
  normalized.includes('jual') ||
  normalized.includes('beli') ||
  normalized.includes('beras') ||
  normalized.includes('cabai') ||
  normalized.includes('sayur') ||
  normalized.includes('buah') ||
  normalized.includes('telur') ||
  normalized.includes('daging') ||
  normalized.includes('ikan') ||
  normalized.includes('madu') ||
  normalized.includes('susu') ||
  normalized.includes('kopi') ||
  normalized.includes('rempah')
) {
  intent = 'products';
  searchQuery = cleanQuery(normalized);
} else if (
  normalized.includes('petani') ||
  normalized.includes('toko') ||
  normalized.includes('mitra') ||
  normalized.includes('penjual') ||
  normalized.includes('alamat') ||
  normalized.includes('lokasi')
) {
  intent = 'sellers';
  searchQuery = cleanQuery(normalized);
} else if (
  normalized.includes('order') ||
  normalized.includes('pesanan') ||
  normalized.includes('transaksi')
) {
  intent = 'orders';
}

return {
  json: {
    message,
    intent,
    searchQuery,
    orderNumber,
    user
  }
};

const message = $node["Classify Intent"].json.message;
const user = $node["Classify Intent"].json.user;
const intent = $node["Classify Intent"].json.intent;
const searchQuery = $node["Classify Intent"].json.searchQuery;
const orderNumber = $node["Classify Intent"].json.orderNumber;
const results = $input.all();

let reply = '';
const greeting = user.id ? `Halo Kak **${user.name}**! ` : 'Halo! ';

if (intent === 'products') {
  if (results.length === 0) {
    reply = searchQuery ? 
      greeting + `Maaf, produk dengan kata kunci "**${searchQuery}**" tidak ditemukan di katalog kami saat ini.` :
      greeting + 'Saat ini belum ada produk segar terdaftar di katalog kami.';
  } else if (results.length === 1) {
    const p = results[0].json;
    const priceFormatted = Number(p.price).toLocaleString('id-ID');
    reply = greeting + `Berikut detail produk **${p.name}**:\n\n` +
      `• Deskripsi: ${p.description || '-'}\n` +
      `• Harga: **Rp ${priceFormatted} per ${p.unit}**\n` +
      `• Stok: **${p.stock} ${p.unit}**\n` +
      `• Toko: **${p.seller_name}** (${p.address})\n` +
      `• Kontak Tani WA: ${p.phone}\n\n` +
      `Anda bisa langsung memesan produk ini di tab **Produk** pada aplikasi.`;
  } else {
    reply = greeting + (searchQuery ? `Berikut produk yang cocok dengan pencarian "**${searchQuery}**":\n\n` : 'Berikut daftar produk segar terbaru di platform kami:\n\n') +
      results.map((r, i) => {
        const p = r.json;
        const priceFormatted = Number(p.price).toLocaleString('id-ID');
        return `${i+1}. **${p.name}**\n   • Harga: Rp ${priceFormatted} per ${p.unit}\n   • Stok: ${p.stock} ${p.unit}\n   • Toko: ${p.seller_name}`;
      }).join('\n\n') +
      '\n\nBuka tab **Produk** untuk melihat lebih lengkap atau melakukan transaksi.';
  }
} else if (intent === 'sellers') {
  if (results.length === 0) {
    reply = searchQuery ? 
      greeting + `Maaf, toko tani dengan nama "**${searchQuery}**" tidak ditemukan.` :
      greeting + 'Belum ada Toko Tani Mitra terdaftar.';
  } else if (results.length === 1) {
    const s = results[0].json;
    reply = greeting + `Berikut profil Toko Tani Mitra **${s.shop_name}**:\n\n` +
      `• Nama Pemilik: ${s.seller_name}\n` +
      `• Alamat: ${s.address}\n` +
      `• Hubungi: **${s.phone}**\n` +
      `• Deskripsi: "${s.shop_description || 'Penyedia komoditas segar pilihan.'}"`;
  } else {
    reply = greeting + 'Berikut daftar Toko Tani Mitra terbaik kami:\n\n' +
      results.map((r, i) => {
        const s = r.json;
        return `${i+1}. **${s.shop_name}** (Pemilik: ${s.seller_name})\n   • Alamat: ${s.address}\n   • Hubungi: ${s.phone}`;
      }).join('\n\n');
  }
} else if (intent === 'orders') {
  if (!user.id) {
    reply = 'Silakan melakukan login terlebih dahulu untuk mengakses riwayat transaksi Anda.';
  } else if (results.length === 0) {
    reply = greeting + 'Anda belum memiliki riwayat transaksi di AgriConnect.';
  } else {
    reply = greeting + 'Berikut status 3 transaksi terbaru Anda:\n\n' +
      results.map((r, i) => {
        const o = r.json;
        const totalFormatted = Number(o.total_price).toLocaleString('id-ID');
        return `${i+1}. **No. Order: ${o.order_number}**\n   • Total: Rp ${totalFormatted}\n   • Status: **${o.status.toUpperCase()}**`;
      }).join('\n\n') +
      '\n\nKetik "*Cek pesanan [No. Order]*" untuk melihat detail pengiriman spesifik.';
  }
} else if (intent === 'specific_order') {
  if (results.length === 0) {
    reply = greeting + `Maaf, pesanan dengan nomor **${orderNumber}** tidak ditemukan, atau Anda tidak berhak melacaknya.`;
  } else {
    const o = results[0].json;
    const totalFormatted = Number(o.total_price).toLocaleString('id-ID');
    const date = new Date(o.created_at).toLocaleString('id-ID', { dateStyle: 'medium', timeStyle: 'short' });
    const statusMap = {
      'pending': 'Menunggu Pembayaran ⏳',
      'confirmed': 'Dikonfirmasi (Sedang Diproses) 📦',
      'shipped': 'Dalam Pengiriman 🚚',
      'delivered': 'Telah Diterima (Selesai) ✓',
      'cancelled': 'Dibatalkan ✕'
    };
    const statusStr = statusMap[o.status] || o.status.toUpperCase();
    reply = greeting + `Berikut detail pesanan Anda **${o.order_number}**:\n\n` +
      `• Tanggal: ${date}\n` +
      `• Total Bayar: **Rp ${totalFormatted}**\n` +
      `• Alamat Kirim: ${o.shipping_address}\n` +
      `• Catatan: ${o.notes || '-'}\n` +
      `• Status: **${statusStr}**`;
  }
}

return {
  json: {
    reply,
    source: 'n8n_database_high_accuracy'
  }
};

const message = $node["Classify Intent"].json.message;
const user = $node["Classify Intent"].json.user || { name: 'Guest', role: 'Guest', id: null };
const normalized = message.toLowerCase();
const greeting = user.id ? `Halo Kak **${user.name}** (${user.role})! ` : 'Halo! ';

let reply = '';

if (normalized.includes('fitur') || normalized.includes('bantuan') || normalized.includes('cara') || normalized.includes('aplikasi') || normalized.includes('menu')) {
  reply = greeting + "Saya adalah **Agri Asisten Bot**, asisten virtual Anda di AgriConnect. Berikut panduan cepat menu utama aplikasi kami:\n\n" +
    "• **Bagi Petani**: Anda dapat mencatat panen di menu **Panen**, mengatur penanaman di menu **Jadwal**, mengelola pengeluaran di **Biaya Produksi**, serta menerbitkan stok barang jualan di menu **Stok**.\n" +
    "• **Bagi Pembeli**: Anda dapat mencari produk segar di menu **Produk**, memasukkannya ke keranjang, melakukan checkout/pemesanan, melacak pengiriman di menu **Pesanan**, dan melakukan review produk.\n\n" +
    "Ada hal spesifik terkait fitur yang ingin Anda tanyakan?";
} else if (normalized.includes('panen') || normalized.includes('tanam') || normalized.includes('pupuk') || normalized.includes('bibit') || normalized.includes('padi') || normalized.includes('hama')) {
  reply = greeting + "Berikut adalah beberapa tips pertanian praktis untuk mengoptimalkan hasil panen Anda:\n\n" +
    "1. **Bibit Unggul**: Gunakan varietas bibit bersertifikat yang tahan terhadap hama setempat.\n" +
    "2. **Pemupukan Berimbang**: Berikan pupuk organik dan anorganik (seperti NPK) sesuai fase pertumbuhan tanaman.\n" +
    "3. **Pengairan**: Gunakan sistem pengairan berkala (intermittent) untuk tanaman padi guna menghemat air dan menekan pertumbuhan gas metana.\n" +
    "4. **Pengendalian Hama**: Lakukan pemantauan rutin dan gunakan pestisida nabati atau musuh alami sebelum beralih ke bahan kimia.\n" +
    "5. **Masa Panen**: Lakukan pemanenan saat 90-95% butir gabah telah menguning untuk kualitas gabah terbaik.";
} else if (normalized.includes('halo') || normalized.includes('hai') || normalized.includes('pagi') || normalized.includes('siang') || normalized.includes('sore') || normalized.includes('malam') || normalized.includes('selamat')) {
  reply = greeting + "Saya adalah **Agri Asisten Bot** 🌾. Ada yang bisa saya bantu hari ini?\n\n" +
    "Anda bisa bertanya kepada saya tentang:\n" +
    "• \"*Apakah ada stok beras merah?*\" untuk mengecek ketersediaan produk.\n" +
    "• \"*Di mana alamat Toko Tani Makmur?*\" untuk mencari tahu profil penjual.\n" +
    "• \"*Cek status pesanan*\" atau nomor pesanan spesifik (seperti *OR-202606110001*) untuk melacak transaksi Anda.";
} else {
  reply = greeting + "Saya adalah **Agri Asisten Bot** yang didukung oleh n8n.\n\n" +
    "Maaf, saya tidak memahami pertanyaan Anda: \"*" + message + "*\".\n\n" +
    "Cobalah untuk menanyakan hal spesifik seperti:\n" +
    "• *Harga produk*: \"Berapa harga cabai merah?\" atau \"Apakah ada stok madu?\"\n" +
    "• *Profil toko tani*: \"Toko Tani Makmur di mana?\"\n" +
    "• *Status pesanan*: \"Cek status pesanan OR-xxxx\" (pastikan Anda sudah login)\n" +
    "• *Bantuan*: \"Panduan menu aplikasi\" atau \"Tips pemupukan padi\"";
}

return {
  json: {
    reply,
    source: 'n8n_generative_bot'
  }
};
